const buildPhoneValueFromUser = (target?: Partial<User> | null): PhoneValue => {
    const parsedPhoneValue = parsePhoneValue(target?.phone);
    const countryCode = typeof target?.phoneCountryCode === 'string' ? target.phoneCountryCode.trim().toUpperCase() : '';
    const phone = typeof target?.phone === 'string' ? target.phone.trim() : '';
    const dialCode = getDialCodeFromCountryCode(countryCode);

    if (!countryCode || !dialCode) {
        return parsedPhoneValue;
    }

    const localNumber = phone.startsWith(dialCode)
        ? phone.slice(dialCode.length).trim()
        : parsedPhoneValue.countryCode === countryCode
            ? parsedPhoneValue.number
            : phone;

    return {
        countryCode,
        dialCode,
        number: localNumber,
        full: localNumber ? `${dialCode} ${localNumber}` : '',
    };
};

const normalizeMediaGallery = (gallery: Array<MediaGalleryItem | string> | undefined | null): MediaGalleryItem[] => {
    if (!Array.isArray(gallery)) {
        return [];
    }
    return gallery
        .map((item, index) => {
            if (typeof item === 'string') {
                const trimmed = item.trim();
                if (!trimmed) return null;
                return {
                    id: `media_${index}_${Math.random().toString(36).slice(2, 7)}`,
                    url: trimmed,
                    mediaType: 'image' as const,
                    order: index
                };
            }
            const url = typeof item?.url === 'string' ? item.url.trim() : '';
            return {
                id: typeof item.id === 'string' && item.id.trim() ? item.id : `media_${index}_${Math.random().toString(36).slice(2, 7)}`,
                url,
                mediaType: item.mediaType === 'video' ? 'video' : 'image',
                order: index
            };
        })
        .filter((item): item is MediaGalleryItem => Boolean(item));
};

const resolveHeroMediaGallery = (branding: Partial<AppearanceFormState['branding']> | undefined): MediaGalleryItem[] => {
    const normalized = normalizeMediaGallery(branding?.heroMediaGallery);
    if (normalized.length > 0) {
        return normalized;
    }
    const fallbackItems: MediaGalleryItem[] = [];
    const imageUrl = (branding?.heroBackgroundImageUrl || '').trim();
    const videoUrl = (branding?.heroBackgroundVideoUrl || '').trim();
    if (imageUrl) {
        fallbackItems.push({
            id: `media_fallback_image_${Math.random().toString(36).slice(2, 7)}`,
            url: imageUrl,
            mediaType: 'image',
            order: fallbackItems.length
        });
    }
    if (videoUrl) {
        fallbackItems.push({
            id: `media_fallback_video_${Math.random().toString(36).slice(2, 7)}`,
            url: videoUrl,
            mediaType: 'video',
            order: fallbackItems.length
        });
    }
    return fallbackItems;
};

