const hasSeoOverrideValues = (override?: SeoOverride) => {
    if (!override) return false;
    return Object.values(override).some((value) => {
        if (value === undefined || value === null) return false;
        if (typeof value === 'string') return value.trim().length > 0;
        if (typeof value === 'number') return Number.isFinite(value);
        if (typeof value === 'boolean') return true;
        return true;
    });
};

const buildSeoOverridePayload = (override?: SeoOverride, enabled?: boolean) => {
    if (!enabled || !override) return undefined;
    const payload: Partial<SeoOverride> = {};
    const setIfString = (key: keyof SeoOverride, value?: string | null) => {
        if (typeof value !== 'string') return;
        const trimmed = value.trim();
        if (trimmed) {
            payload[key] = trimmed as SeoOverride[keyof SeoOverride];
        }
    };

    setIfString('title_en', override.title_en);
    setIfString('title_ar', override.title_ar);
    setIfString('description_en', override.description_en);
    setIfString('description_ar', override.description_ar);
    setIfString('keywords_en', override.keywords_en);
    setIfString('keywords_ar', override.keywords_ar);
    setIfString('canonical_url', override.canonical_url);
    setIfString('robots', override.robots);
    if (override.indexable === false) {
        payload.indexable = false;
    }

    setIfString('og_title_en', override.og_title_en);
    setIfString('og_title_ar', override.og_title_ar);
    setIfString('og_description_en', override.og_description_en);
    setIfString('og_description_ar', override.og_description_ar);
    setIfString('og_image_url', override.og_image_url);
    setIfString('og_type', override.og_type);
    setIfString('og_site_name', override.og_site_name);

    setIfString('twitter_card', override.twitter_card);
    setIfString('twitter_title_en', override.twitter_title_en);
    setIfString('twitter_title_ar', override.twitter_title_ar);
    setIfString('twitter_description_en', override.twitter_description_en);
    setIfString('twitter_description_ar', override.twitter_description_ar);
    setIfString('twitter_image_url', override.twitter_image_url);

    setIfString('jsonld_en', override.jsonld_en);
    setIfString('jsonld_ar', override.jsonld_ar);
    setIfString('locale', override.locale);
    setIfString('locale_alternate', override.locale_alternate);

    if (override.sitemap_priority !== undefined && override.sitemap_priority !== null && `${override.sitemap_priority}`.trim()) {
        const parsed = Number(override.sitemap_priority);
        if (Number.isFinite(parsed)) {
            payload.sitemap_priority = parsed;
        }
    }
    setIfString('sitemap_changefreq', override.sitemap_changefreq);

    return Object.keys(payload).length ? payload : undefined;
};

const normalizePlansForForm = (plans?: Array<Partial<AppearancePlan>>): AppearancePlan[] => {
    if (!Array.isArray(plans) || !plans.length) {
        return DEFAULT_APPEARANCE_FORM.pricing.plans.map((plan) => ({ ...plan, features: [...plan.features] }));
    }
    return plans.slice(0, MAX_PRICING_PLANS).map((plan, index) => ({
        id: (plan?.id && plan.id.trim()) || `plan_${index + 1}`,
        title: plan?.title || '',
        price: plan?.price || '',
        description: plan?.description || '',
        highlight: Boolean(plan?.highlight),
        features: Array.isArray(plan?.features) ? plan.features.filter((feature): feature is string => typeof feature === 'string').map((feature) => feature.trim()).filter(Boolean) : []
    }));
};

