const exportToCSV = (data: any[], filename: string) => {
    if (!data.length) return;
    const headers = Object.keys(data[0]);
    const csvContent = [
        headers.join(','),
        ...data.map(row =>
            headers.map(fieldName => JSON.stringify(row[fieldName] ?? '')).join(',')
        )
    ].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    link.click();
    URL.revokeObjectURL(url);
};

const shareCourse = (
    course: Course,
    platform: 'facebook' | 'instagram' | 'whatsapp'
) => {
    const courseSlug = (course as any)?.slug;
    const coursePath = courseSlug ? `course/${courseSlug}` : `courses/${course.id}`;
    const courseUrl = `${window.location.origin}/${coursePath}`;
    const text = `Check out ${course.title} on BetAcademy`;
    let shareUrl = '';
    switch (platform) {
        case 'facebook':
            shareUrl = `https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(courseUrl)}`;
            break;
        case 'instagram':
            shareUrl = `https://www.instagram.com/?url=${encodeURIComponent(courseUrl)}`;
            break;
        case 'whatsapp':
            shareUrl = `https://wa.me/?text=${encodeURIComponent(`${text} ${courseUrl}`)}`;
            break;
    }

    if (shareUrl) {
        window.open(shareUrl, '_blank', 'width=600,height=400');
    }
};

const COURSE_REQUIRED_FIELDS_REGEX = /title, description, instructor, and thumbnail are required/i;

const getErrorString = (error: unknown): string => {
    if (typeof error === 'string') return error;
    if (error instanceof Error) return error.message;
    return '';
};

const getCourseSaveErrorMessage = (error: unknown, t?: any) => {
    const fallback = t?.courseSaveFailed || 'Failed to save course.';
    const serverMessage = getErrorString(error);
    if (serverMessage && COURSE_REQUIRED_FIELDS_REGEX.test(serverMessage)) {
        return t?.courseRequiredFieldsError || fallback;
    }
    return fallback;
};

const formatCountMessage = (template: string, count: number) => template.replace('{{count}}', count.toString());

const buildImportStudentsMessage = (count: number, enrolled: boolean, t?: any) => {
    const base = formatCountMessage(t?.importStudentsSuccess || 'Successfully imported {{count}} students', count);
    if (enrolled) {
        const suffix = t?.importStudentsEnrolledSuffix || ' and enrolled them';
        return `${base}${suffix}`;
    }
    return base;
};

const buildUserBulkAddMessage = (count: number, t?: any) => {
    const template = t?.userBulkAddSuccess || 'Successfully added {{count}} users';
    return formatCountMessage(template, count);
};

const resolveAttendanceMinutes = (record?: AttendanceRecord) => {
    if (!record) return 0;
    if (typeof record.durationMinutes === 'number') {
        return record.durationMinutes;
    }
    const seconds = typeof record.durationSeconds === 'number' ? record.durationSeconds : 0;
    return Math.max(0, Math.round(seconds / 60));
};

const mergeStaticPageRecords = (records: StaticPageContent[], record: StaticPageContent) => {
    const index = records.findIndex((item) => item.slug === record.slug);
    if (index === -1) {
        return [...records, record];
    }
    const next = [...records];
    next[index] = record;
    return next;
};

const buildCreditReasonDictionary = (t?: any) => ({
    'daily login reward': t?.dailyLoginReward || 'Daily Login Reward',
    'lesson completion reward': t?.lessonReward || 'Lesson Completion Reward',
    'course completion bonus': t?.courseCompletionReward || 'Course completion bonus',
    'quiz pass reward': t?.quizReward || 'Quiz Pass Reward',
    'assignment submission reward': t?.assignmentReward || 'Assignment Submission Reward',
    'manual adjustment': t?.manualAdjustments || 'Manual credit adjustments',
    'manual credit adjustments': t?.manualAdjustments || 'Manual credit adjustments'
});

const resolveCreditReasonLabel = (reason?: string, t?: any, fallback?: string) => {
    if (!reason || !reason.trim()) {
        return fallback || t?.noReasonProvided || 'No reason provided';
    }
    const normalized = reason.trim();
    const dictionary = buildCreditReasonDictionary(t);
    return dictionary[normalized.toLowerCase()] || normalized;
};

const resolveCertificateTypeLabel = (type?: Certificate['type'], t?: any) => {
    if (type === 'COMPLETION') {
        return t?.completion || 'Completion';
    }
    if (type === 'ATTENDANCE') {
        return t?.attendance || 'Attendance';
    }
    return type || '';
};

const resolveRedemptionStatusLabel = (status?: CreditRedemption['status'], t?: any) => {
    if (!status) return '';
    switch (status) {
        case 'PENDING':
            return t?.pending || 'Pending';
        case 'COMPLETED':
            return t?.completed || 'Completed';
        case 'REJECTED':
            return t?.rejected || 'Rejected';
        default:
            return status;
    }
};

const resolveAssignmentTypeLabel = (type?: CourseContentItem['type'], t?: any) => {
    if (type === 'QUIZ') {
        return t?.quiz || 'Quiz';
    }
    if (type === 'ASSIGNMENT') {
        return t?.assignment || 'Assignment';
    }
    if (!type) return '';
    const normalized = type.replace(/_/g, ' ').toLowerCase();
    return normalized.charAt(0).toUpperCase() + normalized.slice(1);
};

const normalizePaymentMethod = (method?: string) => {
    if (!method) return '';
    return method.toString().toUpperCase();
};

const resolvePaymentMethodLabel = (method?: string, t?: any) => {
    if (!method) {
        return t?.unknown || 'Unknown';
    }
    const normalized = normalizePaymentMethod(method);
    const labels: Record<string, string> = {
        ONLINE: t?.onlineMethodLabel || 'Online',
        CASH: t?.cashMethodLabel || 'Cash',
        TRANSFER: t?.transferMethodLabel || 'Bank Transfer',
        MANUAL: t?.manualEntryLabel || 'Manual Entry'
    };
    return labels[normalized] || t?.unknown || method;
};

const getPaymentMethodBadgeClass = (method?: string) => {
    const normalized = normalizePaymentMethod(method);
    if (normalized === 'CASH' || normalized === 'MANUAL') {
        return 'bg-amber-100 text-amber-700';
    }
    if (normalized === 'TRANSFER') {
        return 'bg-blue-100 text-blue-700';
    }
    if (normalized === 'ONLINE') {
        return 'bg-emerald-100 text-emerald-700';
    }
    return 'bg-zinc-100 text-zinc-600';
};

const isOfflinePaymentMethod = (method?: string) => {
    const normalized = normalizePaymentMethod(method);
    return normalized === 'CASH' || normalized === 'TRANSFER' || normalized === 'MANUAL';
};

const buildCourseFinancialSummaries = (
    payments: PaymentRecord[],
    courseLookup: Map<string, Course>,
    studentLookup: Map<string, User>
): CourseFinancialSummary[] => {
    if (!payments.length) {
        return [];
    }
    const summaryMap = new Map<string, CourseFinancialSummary>();
    payments.forEach((payment) => {
        const key = `${payment.courseId || 'unknown'}:${payment.studentId || 'unknown'}`;
        const fallbackCourse = payment.courseId ? courseLookup.get(payment.courseId) : undefined;
        const fallbackStudent = payment.studentId ? studentLookup.get(payment.studentId) : undefined;
        const paymentCoursePrice = typeof payment.coursePrice === 'number' ? payment.coursePrice : Number(fallbackCourse?.price) || 0;
        if (!summaryMap.has(key)) {
            summaryMap.set(key, {
                id: key,
                studentId: payment.studentId,
                studentName: payment.studentName || fallbackStudent?.name || 'Student',
                studentEmail: payment.studentEmail || fallbackStudent?.email || undefined,
                courseId: payment.courseId,
                courseTitle: payment.courseTitle || fallbackCourse?.title || 'Course',
                instructorName: payment.instructorName || fallbackCourse?.instructor || undefined,
                coursePrice: paymentCoursePrice,
                totalPaid: 0,
                remainingBalance: paymentCoursePrice,
                status: 'UNPAID',
                lastPaymentAt: payment.receivedAt || payment.createdAt || null
            });
        }
        const summary = summaryMap.get(key)!;
        const normalizedCoursePrice = paymentCoursePrice || summary.coursePrice || Number(fallbackCourse?.price) || 0;
        if (!summary.coursePrice && normalizedCoursePrice) {
            summary.coursePrice = normalizedCoursePrice;
        }
        if (!summary.studentEmail && fallbackStudent?.email) {
            summary.studentEmail = fallbackStudent.email;
        }
        const amount = Number(payment.amount) || 0;
        summary.totalPaid += amount;
        const targetPrice = summary.coursePrice || normalizedCoursePrice;
        summary.remainingBalance = targetPrice ? Math.max(targetPrice - summary.totalPaid, 0) : 0;
        summary.status = summary.totalPaid <= 0 ? 'UNPAID' : summary.remainingBalance > 0 ? 'PARTIAL' : 'PAID';
        const paymentTimestamp = payment.receivedAt || payment.createdAt;
        if (
            paymentTimestamp &&
            (!summary.lastPaymentAt || new Date(paymentTimestamp).getTime() > new Date(summary.lastPaymentAt).getTime())
        ) {
            summary.lastPaymentAt = paymentTimestamp;
        }
        summaryMap.set(key, summary);
    });
    return Array.from(summaryMap.values()).sort((a, b) => {
        const aTime = a.lastPaymentAt ? new Date(a.lastPaymentAt).getTime() : 0;
        const bTime = b.lastPaymentAt ? new Date(b.lastPaymentAt).getTime() : 0;
        return bTime - aTime;
    });
};

