    const filteredCourses = useMemo(() => {
        const searchValue = courseSearch.trim().toLowerCase();
        let filtered = [...allCourses];

        if (searchValue) {
            filtered = filtered.filter((course) => {
                const title = course.title?.toLowerCase() || '';
                const instructor = course.instructor?.toLowerCase() || '';
                const description = course.description?.toLowerCase() || '';
                return title.includes(searchValue) || instructor.includes(searchValue) || description.includes(searchValue);
            });
        }

        if (courseLevelFilter !== 'ALL') {
            filtered = filtered.filter((course) => course.level === courseLevelFilter);
        }

        if (courseCategoryFilter !== 'All') {
            filtered = filtered.filter((course) => course.category === courseCategoryFilter);
        }

        filtered.sort((a, b) => {
            const aTitle = a.title || '';
            const bTitle = b.title || '';
            const comparison = aTitle.localeCompare(bTitle, lang === 'ar' ? 'ar' : 'en');
            return courseSort === 'AZ' ? comparison : -comparison;
        });

        return filtered;
    }, [allCourses, courseSearch, courseLevelFilter, courseCategoryFilter, courseSort, lang]);

