    const paymentMethodOptions = useMemo(() => {
        const set = new Set<string>();
        safePayments.forEach((payment) => {
            const method = normalizePaymentMethod(payment.paymentMethod);
            if (method) {
                set.add(method);
            }
        });
        return Array.from(set).sort();
    }, [safePayments]);
    const payoutMethodOptions = useMemo(() => {
        const set = new Set<string>();
        safePayouts.forEach((payout) => {
            const method = normalizePaymentMethod(payout.paymentMethod);
            if (method) {
                set.add(method);
            }
        });
        if (!set.size) {
            ['TRANSFER', 'CASH', 'MANUAL', 'ONLINE'].forEach((method) => set.add(method));
        }
        return Array.from(set).sort();
    }, [safePayouts]);

    const orderedPayments = useMemo(() => {
        if (!safePayments.length) return [];
        return [...safePayments].sort((a, b) => {
            const aTime = new Date(a.receivedAt || a.createdAt).getTime();
            const bTime = new Date(b.receivedAt || b.createdAt).getTime();
            return bTime - aTime;
        });
    }, [safePayments]);
    const filteredPayments = useMemo(() => {
        if (!orderedPayments.length) return [];
        return orderedPayments.filter((payment) => {
            const timestamp = new Date(payment.receivedAt || payment.createdAt).getTime();
            if (paymentFilters.studentId && payment.studentId !== paymentFilters.studentId) {
                return false;
            }
            if (paymentFilters.courseId && payment.courseId !== paymentFilters.courseId) {
                return false;
            }
            if (paymentFilters.instructorId && payment.instructorId !== paymentFilters.instructorId) {
                return false;
            }
            if (paymentFilters.paymentMethod) {
                const normalized = normalizePaymentMethod(payment.paymentMethod);
                if (normalized !== paymentFilters.paymentMethod) {
                    return false;
                }
            }
            if (paymentFilters.startDate) {
                const start = new Date(paymentFilters.startDate).getTime();
                if (timestamp < start) {
                    return false;
                }
            }
            if (paymentFilters.endDate) {
                const end = new Date(paymentFilters.endDate);
                end.setHours(23, 59, 59, 999);
                if (timestamp > end.getTime()) {
                    return false;
                }
            }
            return true;
        });
    }, [orderedPayments, paymentFilters]);
    const paymentStats = useMemo(() => {
        if (!filteredPayments.length) {
            return { total: 0, offline: 0, online: 0 };
        }
        const accum = filteredPayments.reduce(
            (acc, payment) => {
                const amount = Number(payment.amount) || 0;
                acc.total += amount;
                if (isOfflinePaymentMethod(payment.paymentMethod)) {
                    acc.offline += amount;
                }
                return acc;
            },
            { total: 0, offline: 0 }
        );
        const online = Math.max(0, accum.total - accum.offline);
        return { total: accum.total, offline: accum.offline, online };
    }, [filteredPayments]);
    const filteredSummaries = useMemo(
        () => buildCourseFinancialSummaries(filteredPayments, courseLookup, userLookup),
        [filteredPayments, courseLookup, userLookup]
    );
    const aggregatedCourseTotals = useMemo(() => {
        if (!filteredSummaries.length) return [];
        const map = new Map<string, { courseId: string; courseTitle: string; totalPaid: number; outstanding: number }>();
        filteredSummaries.forEach((summary) => {
            const entry = map.get(summary.courseId) || {
                courseId: summary.courseId,
                courseTitle: summary.courseTitle,
                totalPaid: 0,
                outstanding: 0
            };
            entry.totalPaid += summary.totalPaid;
            entry.outstanding += summary.remainingBalance;
            map.set(summary.courseId, entry);
        });
        return Array.from(map.values()).sort((a, b) => b.totalPaid - a.totalPaid);
    }, [filteredSummaries]);
    const totalOutstandingBalance = useMemo(
        () => filteredSummaries.reduce((sum, summary) => sum + summary.remainingBalance, 0),
        [filteredSummaries]
    );
    const filteredPaymentCount = filteredPayments.length;
    const paymentMethodBreakdown = useMemo(() => {
        if (!filteredPayments.length) return [];
        const map = new Map<string, { method: string; count: number; volume: number }>();
        filteredPayments.forEach((payment) => {
            const key = normalizePaymentMethod(payment.paymentMethod) || 'MANUAL';
            const entry = map.get(key) || { method: key, count: 0, volume: 0 };
            entry.count += 1;
            entry.volume += Number(payment.amount) || 0;
            map.set(key, entry);
        });
        return Array.from(map.values()).sort((a, b) => b.volume - a.volume);
    }, [filteredPayments]);
    const canResetPaymentFilters = useMemo(() => Object.values(paymentFilters).some(Boolean), [paymentFilters]);

    const orderedPayouts = useMemo(() => {
        if (!safePayouts.length) return [];
        return [...safePayouts].sort((a, b) => {
            const aTime = new Date(a.recordedAt || a.createdAt).getTime();
            const bTime = new Date(b.recordedAt || b.createdAt).getTime();
            return bTime - aTime;
        });
    }, [safePayouts]);
    const filteredPayouts = useMemo(() => {
        if (!orderedPayouts.length) return [];
        return orderedPayouts.filter((payout) => {
            const timestamp = new Date(payout.recordedAt || payout.createdAt).getTime();
            if (payoutFilters.instructorId && payout.instructorId !== payoutFilters.instructorId) {
                return false;
            }
            if (payoutFilters.courseId && payout.courseId !== payoutFilters.courseId) {
                return false;
            }
            if (payoutFilters.paymentMethod) {
                const normalized = normalizePaymentMethod(payout.paymentMethod);
                if (normalized !== payoutFilters.paymentMethod) {
                    return false;
                }
            }
            if (payoutFilters.startDate) {
                const start = new Date(payoutFilters.startDate).getTime();
                if (timestamp < start) {
                    return false;
                }
            }
            if (payoutFilters.endDate) {
                const end = new Date(payoutFilters.endDate);
                end.setHours(23, 59, 59, 999);
                if (timestamp > end.getTime()) {
                    return false;
                }
            }
            return true;
        });
    }, [orderedPayouts, payoutFilters]);
    const payoutStats = useMemo(() => {
        if (!filteredPayouts.length) {
            return { total: 0, average: 0, offline: 0, online: 0, lastRecordedAt: null as string | null };
        }
        const aggregates = filteredPayouts.reduce(
            (acc, payout) => {
                const amount = Number(payout.amount) || 0;
                acc.total += amount;
                if (isOfflinePaymentMethod(payout.paymentMethod)) {
                    acc.offline += amount;
                }
                return acc;
            },
            { total: 0, offline: 0 }
        );
        const online = Math.max(0, aggregates.total - aggregates.offline);
        return {
            total: aggregates.total,
            average: aggregates.total / filteredPayouts.length,
            offline: aggregates.offline,
            online,
            lastRecordedAt: filteredPayouts[0]?.recordedAt || filteredPayouts[0]?.createdAt || null
        };
    }, [filteredPayouts]);
    const payoutMethodBreakdown = useMemo(() => {
        if (!filteredPayouts.length) return [];
        const map = new Map<string, { method: string; count: number; volume: number }>();
        filteredPayouts.forEach((payout) => {
            const key = normalizePaymentMethod(payout.paymentMethod) || 'MANUAL';
            const entry = map.get(key) || { method: key, count: 0, volume: 0 };
            entry.count += 1;
            entry.volume += Number(payout.amount) || 0;
            map.set(key, entry);
        });
        return Array.from(map.values()).sort((a, b) => b.volume - a.volume);
    }, [filteredPayouts]);
    const payoutInstructorBreakdown = useMemo(() => {
        if (!filteredPayouts.length) return [];
        const map = new Map<string, { instructorId: string; instructorName: string; total: number }>();
        filteredPayouts.forEach((payout) => {
            if (!payout.instructorId) {
                return;
            }
            const entry = map.get(payout.instructorId) || {
                instructorId: payout.instructorId,
                instructorName: payout.instructorName || 'Instructor',
                total: 0
            };
            entry.total += Number(payout.amount) || 0;
            map.set(payout.instructorId, entry);
        });
        return Array.from(map.values()).sort((a, b) => b.total - a.total);
    }, [filteredPayouts]);
    const payoutFiltersActive = useMemo(() => Object.values(payoutFilters).some(Boolean), [payoutFilters]);
    const payoutCount = filteredPayouts.length;

    const currencyCode = rewardsConfig?.currencyCode || 'USD';
