    const averageCoursePrice = useMemo(
        () => {
            if (!safeCourses.length) return 0;
            const totalPrice = safeCourses.reduce((sum, course) => sum + (Number(course.price) || 0), 0);
            return totalPrice / safeCourses.length;
        },
        [safeCourses]
    );

    const revenueStats = useMemo(() => {
        if (!safePayments.length) {
            return { total: 0, last30: 0, previous30: 0, deltaPct: null };
        }
        const now = Date.now();
        const THIRTY_DAYS_MS = 30 * 24 * 60 * 60 * 1000;
        let total = 0;
        let last30 = 0;
        let previous30 = 0;
        safePayments.forEach((payment) => {
            const amount = Number(payment.amount) || 0;
            total += amount;
            const timestamp = new Date(payment.receivedAt || payment.createdAt).getTime();
            if (!Number.isFinite(timestamp)) {
                return;
            }
            if (timestamp >= now - THIRTY_DAYS_MS) {
                last30 += amount;
            } else if (timestamp >= now - 2 * THIRTY_DAYS_MS) {
                previous30 += amount;
            }
        });
        const deltaPct = previous30 > 0 ? ((last30 - previous30) / previous30) * 100 : last30 > 0 ? 100 : null;
        return { total, last30, previous30, deltaPct };
    }, [safePayments]);

    const totalRevenue = revenueStats.total;
    const revenueTrendPercentage = typeof revenueStats.deltaPct === 'number' ? revenueStats.deltaPct : null;

