    const platformAtRiskCount = useMemo(() => {
        if (!safeUsers.length) return 0;
        const latestActivityByStudent = new Map<string, number>();
        safeAttendance.forEach((record) => {
            if (!record.userId) return;
            const timestamp = record.lastActiveAt
                ? new Date(record.lastActiveAt).getTime()
                : new Date(record.date).getTime();
            if (!Number.isFinite(timestamp)) return;
            const previous = latestActivityByStudent.get(record.userId);
            if (!previous || timestamp > previous) {
                latestActivityByStudent.set(record.userId, timestamp);
            }
        });
        const now = Date.now();
        const staleThreshold = 7 * 24 * 60 * 60 * 1000;
        return safeUsers
            .filter((user) => user.role === UserRole.STUDENT)
            .filter((student) => {
                const latest = latestActivityByStudent.get(student.id);
                if (!latest) return true;
                return now - latest > staleThreshold;
            }).length;
    }, [safeAttendance, safeUsers]);

