    const revenueData = useMemo(() => {
        if (!safePayments.length) return [];
        const aggregates = new Map<string, { name: string; value: number }>();
        safePayments.forEach((payment) => {
            const timestamp = payment.receivedAt || payment.createdAt;
            if (!timestamp) return;
            const iso = new Date(timestamp).toISOString().slice(0, 7); // YYYY-MM
            const labelDate = new Date(`${iso}-01T00:00:00Z`);
            const label = `${labelDate.toLocaleString(undefined, { month: 'short' })} ${labelDate.getUTCFullYear()}`;
            const current = aggregates.get(iso) || { name: label, value: 0 };
            current.value += Number(payment.amount || 0);
            aggregates.set(iso, current);
        });
        return Array.from(aggregates.entries())
            .sort((a, b) => (a[0] > b[0] ? 1 : -1))
            .map(([, value]) => ({ ...value, value: Number(value.value.toFixed(2)) }));
    }, [safePayments]);
