    const adminTabs: AdminDashboardTab[] = ['OVERVIEW', 'USERS', 'COURSES', 'OFFERS', 'BLOG', 'FINANCIAL', 'CREDITS', 'ATTENDANCE', 'REPORTS', 'MESSAGES', 'PAGES', 'SEO', 'ADS', 'SETTINGS'];
