        if (!paymentForm.studentId) {
            errors.studentId = t?.paymentStudentRequired || (lang === 'ar' ? 'يرجى اختيار الطالب' : 'Please select a student');
        }
        if (!paymentForm.courseId) {
            errors.courseId = t?.paymentCourseRequired || (lang === 'ar' ? 'يرجى اختيار الدورة' : 'Please select a course');
        }
        if (!(Number(paymentForm.amount) > 0)) {
            errors.amount = t?.paymentAmountRequired || (lang === 'ar' ? 'يرجى إدخال مبلغ صالح' : 'Please enter a valid amount');
        }
        setPaymentFormErrors(errors);
        if (Object.keys(errors).length) {
            setManualPaymentNotice(null);
            return;
        }
        setIsSavingPayment(true);
        setManualPaymentNotice(null);
        setPaymentFormErrors({});
        try {
            const payload = {
                studentId: paymentForm.studentId,
                courseId: paymentForm.courseId,
                amount: Number(paymentForm.amount),
                paymentMethod: paymentForm.paymentMethod || 'MANUAL',
                notes: paymentForm.notes?.trim() || undefined,
                receivedAt: paymentForm.receivedAt ? fromRiyadhDateTimeLocal(paymentForm.receivedAt) : undefined,
                collectedBy: paymentForm.collectedBy?.trim() || undefined,
                collectedById: user?.id || null
            };
            const response = await fetch('/api/course-payments', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });
            const saved = await response.json().catch(() => ({}));
            if (!response.ok) {
                throw new Error(saved?.error || t?.paymentCreationError || 'Unable to record payment.');
            }
            setPayments((prev) => [saved, ...prev]);
            onAddCoursePayment?.(saved);
            setManualPaymentNotice({ type: 'success', text: t?.paymentCreationSuccess || 'Payment recorded successfully.' });
            setPaymentForm((prev) => ({
                ...prev,
                amount: '',
                notes: '',
                receivedAt: getRiyadhNowDateTimeLocal()
            }));
        } catch (error) {
            setPaymentFormErrors({
                form: error instanceof Error ? error.message : (t?.paymentCreationError || (lang === 'ar' ? 'تعذر تسجيل الدفعة حالياً.' : 'Unable to record payment right now.'))
            });
        } finally {
            setIsSavingPayment(false);
        }
