    const handleRefundPayment = async (payment: PaymentRecord) => {
        setRefundNotice(null);
        setRefundFormErrors({});
        setRefundingPayment(payment);
        setRefundForm({
            amount: '',
            reason: '',
            isPartialRefund: false
        });
        
        // Check refund eligibility
        try {
            const response = await fetch(`/api/refunds/check/${payment.id}`);
            const data = await response.json();
            
            if (response.ok && data.success) {
                setRefundEligibility(data.data);
                if (!data.data.canRefund) {
                    setRefundNotice({
                        type: 'error',
                        text: data.data.reason || t?.refundEligibilityUnavailable || 'This payment cannot be refunded'
                    });
                }
            } else {
                setRefundEligibility({ canRefund: false, reason: t?.refundEligibilityError || 'Unable to check refund eligibility', remainingAmount: 0 });
                setRefundNotice({ type: 'error', text: t?.refundEligibilityError || 'Unable to check refund eligibility' });
            }
        } catch (error) {
            console.error('Error checking refund eligibility:', error);
            setRefundEligibility({ canRefund: false, reason: t?.refundEligibilityError || 'Error checking refund eligibility', remainingAmount: 0 });
            setRefundNotice({ type: 'error', text: t?.refundEligibilityError || 'Error checking refund eligibility' });
        }
    };

    const handleRefundSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
        event.preventDefault();
        if (!refundingPayment || !refundEligibility?.canRefund) return;

        const refundAmount = refundForm.isPartialRefund ? parseFloat(refundForm.amount) : undefined;

        // Validate partial refund amount
        if (refundForm.isPartialRefund) {
            if (!refundAmount || refundAmount <= 0) {
                setRefundFormErrors({ amount: t?.refundAmountInvalid || 'Please enter a valid refund amount' });
                return;
            }
            if (refundAmount > refundEligibility.remainingAmount) {
                setRefundFormErrors({
                    amount: t?.refundAmountExceeds || 'Refund amount exceeds the allowable limit'
                });
                return;
            }
        }

        setIsProcessingRefund(true);
        setRefundNotice(null);
        setRefundFormErrors({});

        try {
            const response = await fetch(`/api/refunds/${refundingPayment.id}`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    amount: refundAmount,
                    reason: refundForm.reason.trim() || undefined,
                }),
            });

            const data = await response.json();

            if (response.ok && data.success) {
                setFinancialBanner({ 
                    type: 'success', 
                    message: t?.refundProcessedSuccess || 'Refund processed successfully'
                });
                setRefundingPayment(null);
                
                // Refresh payments list to show updated status
                // Note: In a real implementation, you might want to update the payment status locally
                // or add a refunds column to show refunded amounts
            } else {
                setRefundNotice({
                    type: 'error',
                    text: data.message || t?.refundProcessError || 'Failed to process refund'
                });
            }
        } catch (error) {
            console.error('Error processing refund:', error);
            setRefundNotice({ 
                type: 'error', 
                text: t?.refundProcessError || 'Error processing refund. Please try again.'
            });
        } finally {
            setIsProcessingRefund(false);
        }
    };

