    const adjustPaymentsForBalance = async (record: CourseFinancialSummary, targetTotal: number, note?: string) => {
        const currentTotal = Number(record.totalPaid) || 0;
        const delta = Number((targetTotal - currentTotal).toFixed(2));
        if (Math.abs(delta) < 0.01) {
            return;
        }
        if (delta > 0) {
            const response = await fetch('/api/course-payments', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    studentId: record.studentId,
                    courseId: record.courseId,
                    amount: delta,
                    paymentMethod: 'MANUAL',
                    collectedBy: user?.name || 'Admin',
                    collectedById: user?.id || null,
                    notes: note?.trim() || t?.balanceAdjustmentNote || 'Balance adjustment'
                })
            });
            const saved = await response.json().catch(() => ({}));
            if (!response.ok) {
                throw new Error(saved?.error || t?.paymentCreationError || 'Unable to record adjustment payment.');
            }
            setPayments((prev) => [saved, ...prev]);
            onAddCoursePayment?.(saved);
            return;
        }
        let remaining = Math.abs(delta);
        const learnerPayments = orderedPayments.filter(
            (payment) => payment.studentId === record.studentId && payment.courseId === record.courseId
        );
        if (!learnerPayments.length) {
            throw new Error(t?.noPaymentsForLearner || 'No payments to adjust for this learner.');
        }
        for (const payment of learnerPayments) {
            if (remaining <= 0.01) break;
            const paymentAmount = Number(payment.amount) || 0;
            if (paymentAmount <= remaining + 0.01) {
                await deletePaymentRecord(payment.id);
                remaining = Number((remaining - paymentAmount).toFixed(2));
            } else {
                const updatedAmount = Number((paymentAmount - remaining).toFixed(2));
                await patchPaymentRecord(payment.id, {
                    amount: updatedAmount,
                    notes: note?.trim() ? note.trim() : payment.notes || null
                });
                remaining = 0;
                break;
            }
        }
        if (remaining > 0.01) {
            throw new Error(t?.balanceAdjustInsufficient || 'Unable to adjust payments to requested total.');
        }
    };

