    const handleDeleteLearnerBalance = async (record: CourseFinancialSummary) => {
        const confirmed = typeof window === 'undefined'
            ? true
            : await confirm({
                title: (t?.confirmDeleteLearnerBalance || 'Delete all payments for this learner?').replace('{name}', record.studentName),
                confirmText: t?.delete || 'Delete',
                cancelText: t?.cancel || 'Cancel'
            });
        if (!confirmed) {
            return;
        }
        try {
            const response = await fetch(`/api/course-payments/by-student/${record.studentId}/${record.courseId}`, { method: 'DELETE' });
            const payload = await response.json().catch(() => ({}));
            if (!response.ok) {
                throw new Error(payload?.error || t?.balanceDeleteError || 'Unable to delete learner payments.');
            }
            const ids: string[] = Array.isArray(payload.ids) ? payload.ids : [];
            if (ids.length) {
                const removeSet = new Set(ids);
                setPayments((prev) => prev.filter((payment) => {
                    const shouldRemove = removeSet.has(payment.id);
                    if (shouldRemove) {
                        onDeleteCoursePayment?.(payment.id);
                    }
                    return !shouldRemove;
                }));
            }
            setFinancialBanner({ type: 'success', message: t?.balanceDeleteSuccess || 'Learner payments deleted.' });
        } catch (error) {
            setFinancialBanner({
                type: 'error',
                message: error instanceof Error ? error.message : (t?.balanceDeleteError || 'Unable to delete learner payments.')
            });
        }
    };

