    const requestPageContent = useCallback(
        async (slug: string, options?: { signal?: AbortSignal; silent?: boolean }) => {
            if (!slug) return null;
            const { signal, silent } = options || {};
            if (!silent) {
                setIsLoadingPage(true);
            }
            setPageError(null);
            try {
                const response = await fetch(`/api/static-pages/${slug}`, { signal });
                if (!response.ok) {
                    throw new Error(t?.pageLoadError || 'Failed to load page content');
                }
                const data: StaticPageContent = await response.json();
                syncStaticPageRecord(data);
                setPageDrafts((prev) => ({ ...prev, [slug]: data.content || '' }));
                return data;
            } catch (error) {
                if ((error as Error)?.name === 'AbortError') {
                    return null;
                }
                setPageError(error instanceof Error ? error.message : (t?.pageLoadError || 'Unable to load page content'));
                return null;
            } finally {
                if (!silent) {
                    setIsLoadingPage(false);
                }
            }
        },
        [syncStaticPageRecord]
    );

    const fetchCareerApplications = useCallback(
        async (options?: { signal?: AbortSignal; silent?: boolean }) => {
            if (selectedPageSlug !== 'career') return;
            const silent = options?.silent ?? false;
            let signal = options?.signal;
            if (!signal) {
                const controller = new AbortController();
                careerApplicationsAbortRef.current?.abort();
                careerApplicationsAbortRef.current = controller;
                signal = controller.signal;
            }
            if (!silent) {
                setIsLoadingCareerApplications(true);
            }
            setCareerApplicationsError(null);
            try {
                const response = await fetch('/api/careers/applications', { signal });
                if (!response.ok) {
                    const payload = await response.json().catch(() => ({}));
                    throw new Error(payload?.error || 'Failed to load applications');
                }
                const data: CareerApplication[] = await response.json();
                setCareerApplications(Array.isArray(data) ? data : []);
            } catch (error) {
                if ((error as Error)?.name === 'AbortError') {
                    return;
                }
                setCareerApplicationsError(error instanceof Error ? error.message : (t?.careerApplicationsError || 'Unable to load applications.'));
            } finally {
                if (!silent) {
                    setIsLoadingCareerApplications(false);
                }
                if (!options?.signal) {
                    careerApplicationsAbortRef.current = null;
                }
            }
        },
        [selectedPageSlug, t]
    );

