    const handleSavePage = async () => {
        if (!selectedPageSlug) return;
        setIsSavingPage(true);
        setPageError(null);
        setPageSuccess(null);
        try {
            const meta = getStaticPageDefinition(selectedPageSlug);
            const contentPayload = selectedPageSlug === 'career'
                ? serializeCareerJobs(careerJobs)
                : selectedPageSlug === 'services'
                    ? serializeServicesPageContent(servicesPageDraft)
                    : selectedPageSlug === 'home'
                        ? serializeHomePageContent(homePageDraft)
                : (pageDrafts[selectedPageSlug] || '');
            const response = await fetch(`/api/static-pages/${selectedPageSlug}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    content: contentPayload,
                    title: meta?.title,
                    updatedBy: user?.id
                })
            });
            if (!response.ok) {
                const payload = await response.json().catch(() => ({}));
                throw new Error(payload?.error || 'Failed to save page content');
            }
            const data: StaticPageContent = await response.json();
            syncStaticPageRecord(data);
            setPageDrafts((prev) => ({ ...prev, [selectedPageSlug]: data.content || '' }));
            setPageSuccess(t?.pageSaveSuccess || 'Page updated successfully');
        } catch (error) {
            setPageError(error instanceof Error ? error.message : 'Unable to save page content');
        } finally {
            setIsSavingPage(false);
        }
    };

    const handleEditUser = async (updatedUser: User) => {
        try {
            const payload: any = {
                name: updatedUser.name,
                email: updatedUser.email,
                nationalId: updatedUser.nationalId,
                phone: (updatedUser as any).phone || null,
                phoneCountryCode: (updatedUser as any).phoneCountryCode || null,
                role: updatedUser.role,
                status: updatedUser.status,
                followUpStatus: (updatedUser as any).followUpStatus ?? null,
                gender: updatedUser.gender || null,
                specialization: updatedUser.specialization || null
            };
            // Include password only if it's been set
            if ((updatedUser as any).password && (updatedUser as any).password.trim() !== '') {
                payload.password = (updatedUser as any).password;
            }
            const response = await fetch(`/api/users/${updatedUser.id}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });
            const responseData: any = await response.json().catch(() => ({}));
            if (!response.ok) {
                throw new Error(responseData?.error || 'Failed to update user');
            }

            const savedUser = responseData as User;
            const nextUsers = users.map((u) => (u.id === savedUser.id ? savedUser : u));
            syncUsers(nextUsers);
            setEditingUser(null);
            await refreshUsersFromServer().catch((refreshError) => {
                console.error('User refresh after update failed:', refreshError);
            });
        } catch (error) {
            console.error('Error updating user:', error);
            notify('error', t?.userUpdateError || 'Failed to update user. Please try again.');
        }
    };

    const isValidEmail = (email: string): boolean => {
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        return emailRegex.test(email);
    };

    const handleCreateUser = async () => {
        const errors: { name?: string; email?: string; role?: string } = {};
        if (!newUser.name?.trim()) {
            errors.name = t?.errors?.validationRequired || (lang === 'ar' ? 'هذا الحقل مطلوب' : 'This field is required');
        }
        if (!newUser.email?.trim()) {
            errors.email = t?.errors?.validationRequired || (lang === 'ar' ? 'هذا الحقل مطلوب' : 'This field is required');
        }
        if (!newUser.role) {
            errors.role = t?.errors?.validationRequired || (lang === 'ar' ? 'هذا الحقل مطلوب' : 'This field is required');
        }
        if (Object.keys(errors).length) {
            setNewUserErrors(errors);
            return;
        }

        // Validate email format
        const trimmedEmail = newUser.email.trim();
        if (!isValidEmail(trimmedEmail)) {
            setNewUserErrors({ email: t?.errors?.validationInvalidEmail || (lang === 'ar' ? 'يرجى إدخال بريد إلكتروني صحيح' : 'Please enter a valid email address') });
            return;
        }

        setNewUserErrors({});
        
        try {
            const response = await fetch('/api/users', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    name: newUser.name,
                    email: newUser.email,
                    nationalId: newUser.nationalId?.trim() || undefined,
                    phone: (newUser as any).phone?.trim() || undefined,
                    phoneCountryCode: (newUser as any).phone?.trim() ? (newUser as any).phoneCountryCode?.trim() || undefined : undefined,
                    role: newUser.role,
                    status: newUser.status || 'Active',
                    gender: newUser.gender || undefined,
                    specialization: newUser.specialization?.trim() || undefined,
                    password: 'password123' // Default password
                })
            });
            const payload: any = await response.json().catch(() => ({}));
            if (!response.ok) {
                throw new Error(payload?.error || 'Failed to create user');
            }

            const createdUser = payload as User;
            const nextUsers = [...users, createdUser];
            syncUsers(nextUsers);
            setCreatingUser(false);
            setNewUser({ name: '', email: '', nationalId: '', role: UserRole.STUDENT, status: 'Active' });
            setNewUserPhoneValue(parsePhoneValue(''));
            setNewUserErrors({});
            await refreshUsersFromServer().catch((refreshError) => {
                console.error('User refresh after create failed:', refreshError);
            });
        } catch (error) {
            console.error('Error creating user:', error);
            notify('error', t?.userCreateError || 'Failed to create user. Please try again.');
        }
    };

    const handleDeleteUser = async (id: string) => {
        if (!await confirm({
            title: t?.confirmDeleteUser || 'Delete user?',
            confirmText: t?.delete || 'Delete',
            cancelText: t?.cancel || 'Cancel'
        })) return;
        try {
            const response = await fetch(`/api/users/${id}`, { method: 'DELETE' });
            const payload: any = await response.json().catch(() => ({}));
            if (!response.ok) {
                throw new Error(payload?.error || 'Failed to delete user');
            }

            const remaining = users.filter((u) => u.id !== id);
            syncUsers(remaining);
            if (viewingUser?.id === id) {
                setViewingUser(null);
            }
            if (editingUser?.id === id) {
                setEditingUser(null);
            }
            await refreshUsersFromServer().catch((refreshError) => {
                console.error('User refresh after delete failed:', refreshError);
            });
        } catch (error) {
            console.error('Error deleting user:', error);
            notify('error', t?.deleteUserError || 'Failed to delete user. Please try again.');
        }
    };

    const handleOpenEnrollmentModal = async (userId: string) => {
        setEnrollingUserId(userId);
        setSelectedEnrollmentCourse('');
        setEnrollmentMessage(null);
        setEnrollmentErrors({});
        setLoadingEnrollments(true);
        
        try {
            // Fetch current enrollments for this user
            const response = await fetch(`/api/admin/user/${userId}/enrollments`);
            if (response.ok) {
                const enrollments = await response.json();
                setUserEnrollments(enrollments);
            }
        } catch (error) {
            console.error('Error loading enrollments:', error);
        } finally {
            setLoadingEnrollments(false);
        }
    };

    const handleEnrollStudent = async () => {
        if (!enrollingUserId || !selectedEnrollmentCourse) {
            setEnrollmentErrors({ courseId: t?.adminSelectCourseToEnroll || (lang === 'ar' ? 'يرجى اختيار دورة' : 'Please select a course') });
            return;
        }

        setIsEnrolling(true);
        setEnrollmentMessage(null);
        setEnrollmentErrors({});

        try {
            const response = await fetch('/api/admin/enroll-student', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    userId: enrollingUserId,
                    courseId: selectedEnrollmentCourse,
                    adminId: user.id
                })
            });

            const payload = await response.json();

            if (!response.ok) {
                throw new Error(payload?.error || 'Failed to enroll student');
            }

            setEnrollmentMessage({
                type: 'success',
                text: t?.adminEnrollmentSuccess || 'Student enrolled successfully'
            });

            // Refresh enrollments list
            const enrollmentsResponse = await fetch(`/api/admin/user/${enrollingUserId}/enrollments`);
            if (enrollmentsResponse.ok) {
                const enrollments = await enrollmentsResponse.json();
                setUserEnrollments(enrollments);
            }

            // Refresh users list
            await refreshUsersFromServer().catch((refreshError) => {
                console.warn('Failed to refresh users after enrollment:', refreshError);
            });

            // Clear selection
            setSelectedEnrollmentCourse('');
        } catch (error) {
            console.error('Error enrolling student:', error);
            const message = error instanceof Error ? error.message : (t?.adminEnrollmentError || 'Failed to enroll student');
            setEnrollmentMessage(null);
            setEnrollmentErrors({ form: message });
        } finally {
            setIsEnrolling(false);
        }
    };
    
    const handleDeleteCourse = async (id: string) => {
        if (!onUpdateCourses) return;
        if (!await confirm({
            title: t?.confirmDeleteCourse || 'Delete course?',
            confirmText: t?.delete || 'Delete',
            cancelText: t?.cancel || 'Cancel'
        })) return;
        try {
            const response = await fetch(`/api/courses/${id}`, { method: 'DELETE' });
            const payload: any = await response.json().catch(() => ({}));
            if (!response.ok) {
                throw new Error(payload?.error || 'Failed to delete course');
            }
            onUpdateCourses(allCourses.filter((c) => c.id !== id));
            await refreshCoursesFromServer().catch((refreshError) => {
                console.error('Admin course refresh after delete failed', refreshError);
            });
        } catch (error) {
            console.error('Admin delete course failed', error);
            notify('error', t?.courseDeleteError || 'Unable to delete course');
        }
    };
    
    const handleSaveCourse = async (updatedCourse: Course) => {
        if (!onUpdateCourses) return;

        try {
            if (isCreatingCourse || updatedCourse.id.startsWith('new_')) {
                const response = await fetch('/api/courses', {
                    method: 'POST',
                    headers: { 
                        'Content-Type': 'application/json',
                        'Accept-Language': lang === 'ar' ? 'ar' : 'en'
                    },
                    body: JSON.stringify(updatedCourse)
                });
                const payload = await response.json().catch(() => ({}));
                if (!response.ok) {
                    const errorMsg = payload?.error || (lang === 'ar' ? 'فشل إنشاء الدورة' : 'Failed to create course');
                    throw new Error(errorMsg);
                }
                const createdCourse = payload as Course;
                onUpdateCourses([...allCourses, createdCourse]);
            } else {
                const response = await fetch(`/api/courses/${updatedCourse.id}`, {
                    method: 'PUT',
                    headers: { 
                        'Content-Type': 'application/json',
                        'Accept-Language': lang === 'ar' ? 'ar' : 'en'
                    },
                    body: JSON.stringify(updatedCourse)
                });
                const payload = await response.json().catch(() => ({}));
                if (!response.ok) {
                    const errorMsg = payload?.error || (lang === 'ar' ? 'فشل تحديث الدورة' : 'Failed to update course');
                    throw new Error(errorMsg);
                }
                const savedCourse = payload as Course;
                const nextCourses = allCourses.map((c) => (c.id === savedCourse.id ? savedCourse : c));
                onUpdateCourses(nextCourses);
            }
            setIsCreatingCourse(false);
            setEditingCourse(null);
            await refreshCoursesFromServer().catch((refreshError) => {
                console.error('Admin course refresh failed', refreshError);
            });
        } catch (error) {
            console.error('Admin course save failed', error);
            const errorMessage = error instanceof Error ? error.message : (lang === 'ar' ? 'فشل حفظ الدورة' : 'Failed to save course');
            notify('error', errorMessage);
        }
    };

    const handleAdminImport = async (newUsers: Partial<User>[]) => {
        try {
            // Get access token from localStorage if available
            const savedUser = localStorage.getItem('betacademy_user');
            const accessToken = savedUser ? JSON.parse(savedUser).accessToken : null;
            
            const headers: Record<string, string> = { 'Content-Type': 'application/json' };
            if (accessToken) {
                headers['Authorization'] = `Bearer ${accessToken}`;
            }
            
            // Call the bulk import API
            const response = await fetch('/api/users/bulk-import', {
                method: 'POST',
                headers,
                credentials: 'include',
                body: JSON.stringify({ 
                    users: newUsers.map(u => ({
                        name: u.name || 'Unknown',
                        email: u.email || '',
                        role: 'STUDENT',
                        phone: u.phone,
                        password: 'password123'
                    }))
                })
            });
            
            const result = await response.json().catch(() => ({}));
            
            if (!response.ok) {
                throw new Error(result?.error || 'Failed to import users');
            }
            
            const createdUsers = result.users || [];
            
            // Update local state with the created users from the server
            const nextUsers = [...users, ...createdUsers];
            syncUsers(nextUsers);
            
            // Show success message
            const successMsg = buildUserBulkAddMessage(result.created, t);
            const errorMsg = result.failed > 0 ? `\n${result.failed} user(s) failed to import.` : '';
            notify('success', successMsg + errorMsg);
            
            // Refresh the user list from the server
            const usersRes = await fetch('/api/users');
            if (usersRes.ok) {
                const allUsers = await usersRes.json();
                syncUsers(allUsers);
            }
        } catch (error) {
            console.error('Admin import error', error);
            notify('error', t?.importStudentsError || 'Failed to import users. Please try again.');
        }
    };

