    const handleAddPlan = () => {
        setAppearanceForm((prev) => {
            if (prev.pricing.plans.length >= MAX_PRICING_PLANS) {
                return prev;
            }
            const nextIndex = prev.pricing.plans.length + 1;
            const nextPlan: AppearancePlan = {
                id: `plan_${nextIndex}`,
                title: '',
                price: '',
                description: '',
                highlight: false,
                features: []
            };
            return {
                ...prev,
                pricing: {
                    ...prev.pricing,
                    plans: [...prev.pricing.plans, nextPlan]
                }
            };
        });
    };

    const handleRemovePlan = (index: number) => {
        setAppearanceForm((prev) => {
            if (prev.pricing.plans.length <= 1) {
                return prev;
            }
            const plans = prev.pricing.plans.filter((_, idx) => idx !== index);
            return {
                ...prev,
                pricing: {
                    ...prev.pricing,
                    plans
                }
            };
        });
    };

    const handleSaveAppearance = async (event?: React.FormEvent) => {
        event?.preventDefault();
        setIsSavingAppearance(true);
        setAppearanceNotice(null);
        try {
            const heroMode = appearanceForm.branding.heroBackgroundMode;
            const heroMediaGallery = normalizeMediaGallery(appearanceForm.branding.heroMediaGallery);
            const firstImage = heroMediaGallery.find((item) => item.mediaType === 'image' && item.url.trim());
            const firstVideo = heroMediaGallery.find((item) => item.mediaType === 'video' && item.url.trim());
            const hasHeroImage = Boolean(firstImage);
            const hasHeroVideo = Boolean(firstVideo);
            if (heroMode === 'image' && !hasHeroImage) {
                setAppearanceNotice({
                    type: 'error',
                    text: t?.heroBackgroundImageRequired || (t?.lang === 'ar'
                        ? 'يرجى إضافة صورة واحدة على الأقل قبل حفظ وضع الصورة.'
                        : 'Please add at least one image before saving image mode.')
                });
                return;
            }
            if (heroMode === 'video' && !hasHeroVideo) {
                setAppearanceNotice({
                    type: 'error',
                    text: t?.heroBackgroundVideoRequired || (t?.lang === 'ar'
                        ? 'يرجى إضافة فيديو واحد على الأقل قبل حفظ وضع الفيديو.'
                        : 'Please add at least one video before saving video mode.')
                });
                return;
            }
            const brandingPayload = {
                ...appearanceForm.branding,
                heroMediaGallery,
                heroBackgroundImageUrl: firstImage?.url || '',
                heroBackgroundVideoUrl: firstVideo?.url || ''
            };
            const payloadBody = {
                branding: brandingPayload,
                pricing: {
                    headline: appearanceForm.pricing.headline,
                    subheading: appearanceForm.pricing.subheading,
                    ctaLabel: appearanceForm.pricing.ctaLabel,
                    plans: appearanceForm.pricing.plans.map((plan) => ({
                        ...plan,
                        features: plan.features.filter((feature) => feature && feature.trim())
                    }))
                },
                updatedBy: user?.id
            };
            const response = await fetch('/api/tenant/appearance', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payloadBody)
            });
            const payload = await response.json().catch(() => ({}));
            if (!response.ok) {
                throw new Error(payload?.error || t?.appearanceSaveError || 'Unable to save appearance settings');
            }
            const nextBranding = { ...DEFAULT_APPEARANCE_FORM.branding, ...(payload?.branding || {}) };
            nextBranding.heroMediaGallery = resolveHeroMediaGallery(nextBranding);
            setAppearanceForm({
                branding: nextBranding,
                pricing: {
                    headline: payload?.pricing?.headline || '',
                    subheading: payload?.pricing?.subheading || '',
                    ctaLabel: payload?.pricing?.ctaLabel || '',
                    plans: normalizePlansForForm(payload?.pricing?.plans)
                }
            });
            setAppearanceUpdatedAt(payload?.updatedAt || null);
            setAppearanceNotice({
                type: 'success',
                text: isMainSite
                    ? (t?.appearanceSaveSuccessCentral || (t?.lang === 'ar' ? 'تم تحديث الهوية البصرية للنطاق المركزي.' : 'Branding updated for the central domain.'))
                    : (t?.appearanceSaveSuccess || (t?.lang === 'ar' ? 'تم تحديث العلامة لهذا المستأجر.' : 'Branding updated for this tenant.'))
            });
            window.dispatchEvent(new Event('tenant-appearance-updated'));
        } catch (error) {
            setAppearanceNotice({
                type: 'error',
                text: error instanceof Error ? error.message : t?.appearanceSaveError || 'Unable to save appearance settings'
            });
        } finally {
            setIsSavingAppearance(false);
        }
    };

    const handleSaveEmailSettings = async (event?: React.FormEvent) => {
        event?.preventDefault();
        setIsSavingEmailSettings(true);
        setEmailSettingsNotice(null);
        try {
            const payloadBody = {
                smtpHost: emailSettingsForm.smtpHost,
                smtpPort: Number.parseInt(emailSettingsForm.smtpPort, 10) || 587,
                smtpUser: emailSettingsForm.smtpUser,
                smtpPass: emailSettingsForm.smtpPass,
                smtpFrom: emailSettingsForm.smtpFrom,
                smtpSecure: emailSettingsForm.smtpSecure
            };
            const response = await fetch('/api/tenant/email-settings', {
                method: 'PUT',
                credentials: 'include',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payloadBody)
            });
            const payload = await response.json().catch(() => ({}));
            if (!response.ok) {
                throw new Error(payload?.error || 'Unable to save email settings');
            }
            setEmailSettingsForm((prev) => ({
                ...prev,
                smtpHost: payload?.smtpHost || prev.smtpHost,
                smtpPort: String(payload?.smtpPort || prev.smtpPort || 587),
                smtpUser: payload?.smtpUser || prev.smtpUser,
                smtpFrom: payload?.smtpFrom || prev.smtpFrom,
                smtpSecure: Boolean(payload?.smtpSecure),
                smtpPass: ''
            }));
            setEmailSettingsMeta({
                scope: payload?.scope === 'tenant' ? 'tenant' : 'central',
                inheritedForTenant: Boolean(payload?.inheritedForTenant),
                hasPassword: Boolean(payload?.hasPassword),
                updatedAt: payload?.updatedAt || null
            });
            setEmailSettingsNotice({
                type: 'success',
                text: t?.saas?.superAdmin?.emailSettings?.messages?.saveSuccess || 'Email SMTP settings updated successfully.'
            });
        } catch (error) {
            let errorMsg = t?.saas?.superAdmin?.emailSettings?.messages?.saveError || 'Unable to save email settings';
            if (error instanceof Error) {
                // Translate common backend error messages
                if (error.message.includes('SMTP host, port, user, and from address are required')) {
                    errorMsg = t?.saas?.superAdmin?.emailSettings?.messages?.fieldsRequired || 'SMTP host, port, user, and from address are required.';
                } else if (error.message.includes('SMTP password is required')) {
                    errorMsg = t?.saas?.superAdmin?.emailSettings?.messages?.passwordRequired || 'SMTP password is required.';
                } else {
                    errorMsg = error.message;
                }
            }
            setEmailSettingsNotice({
                type: 'error',
                text: errorMsg
            });
        } finally {
            setIsSavingEmailSettings(false);
        }
    };

