    const handleSavePaymentGateways = async (event?: React.FormEvent) => {
        event?.preventDefault();
        const missing: string[] = [];
        if (paymentConfigForm.paypalEnabled && (!paymentConfigForm.paypalClientId.trim() || !paymentConfigForm.paypalSecretKey.trim())) {
            missing.push('PayPal');
        }
        if (paymentConfigForm.stripeEnabled && (!paymentConfigForm.stripePublicKey.trim() || !paymentConfigForm.stripeSecretKey.trim())) {
            missing.push('Stripe');
        }
        if (missing.length) {
            setPaymentNotice({
                type: 'error',
                text:
                    (t.paymentGatewaysValidation || 'Add credentials for enabled gateways: ') +
                    missing.join(', ')
            });
            return;
        }
        setIsSavingPaymentConfig(true);
        setPaymentNotice(null);
        try {
            const payloadBody = {
                paypalEnabled: paymentConfigForm.paypalEnabled,
                paypalClientId: paymentConfigForm.paypalClientId.trim(),
                paypalSecretKey: paymentConfigForm.paypalSecretKey.trim(),
                stripeEnabled: paymentConfigForm.stripeEnabled,
                stripePublicKey: paymentConfigForm.stripePublicKey.trim(),
                stripeSecretKey: paymentConfigForm.stripeSecretKey.trim(),
                stripeWebhookSecret: paymentConfigForm.stripeWebhookSecret.trim(),
                stripePriceBasicMonthly: paymentConfigForm.stripePriceBasicMonthly.trim(),
                stripePriceBasicYearly: paymentConfigForm.stripePriceBasicYearly.trim(),
                stripePriceProMonthly: paymentConfigForm.stripePriceProMonthly.trim(),
                stripePriceProYearly: paymentConfigForm.stripePriceProYearly.trim(),
                stripePriceEnterpriseMonthly: paymentConfigForm.stripePriceEnterpriseMonthly.trim(),
                stripePriceEnterpriseYearly: paymentConfigForm.stripePriceEnterpriseYearly.trim(),
                planBasicMonthlyAmount: paymentConfigForm.planBasicMonthlyAmount ? parseFloat(paymentConfigForm.planBasicMonthlyAmount) : null,
                planBasicMonthlyCurrency: paymentConfigForm.planBasicMonthlyCurrency || 'USD',
                planProMonthlyAmount: paymentConfigForm.planProMonthlyAmount ? parseFloat(paymentConfigForm.planProMonthlyAmount) : null,
                planProMonthlyCurrency: paymentConfigForm.planProMonthlyCurrency || 'USD',
                planEnterpriseMonthlyAmount: paymentConfigForm.planEnterpriseMonthlyAmount ? parseFloat(paymentConfigForm.planEnterpriseMonthlyAmount) : null,
                planEnterpriseMonthlyCurrency: paymentConfigForm.planEnterpriseMonthlyCurrency || 'USD',
                updatedBy: user?.id
            };
            // Use tenant-scoped endpoint for tenant admins, global endpoint for super admins
            const endpoint = user?.role === 'SUPER_ADMIN' ? '/api/payment-gateways' : '/api/admin/payment-gateway/config';
            const response = await fetch(endpoint, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payloadBody)
            });
            const payload = await response.json().catch(() => ({}));
            if (!response.ok) {
                throw new Error(payload?.error || t.paymentGatewaysSaveError || 'Unable to update payment gateways');
            }
            // Handle both formats: tenant endpoint wraps in { data: {...} }, global endpoint returns directly
            const configData = payload.data || payload;
            const sanitized: PaymentGatewayConfig = {
                paypalEnabled: Boolean(configData.paypalEnabled),
                paypalClientId: configData.paypalClientId || '',
                paypalSecretKey: configData.paypalSecretKey || '',
                stripeEnabled: Boolean(configData.stripeEnabled),
                stripePublicKey: configData.stripePublicKey || '',
                stripeSecretKey: configData.stripeSecretKey || '',
                stripeWebhookSecret: configData.stripeWebhookSecret || '',
                stripePriceBasicMonthly: configData.stripePriceBasicMonthly || '',
                stripePriceBasicYearly: configData.stripePriceBasicYearly || '',
                stripePriceProMonthly: configData.stripePriceProMonthly || '',
                stripePriceProYearly: configData.stripePriceProYearly || '',
                stripePriceEnterpriseMonthly: configData.stripePriceEnterpriseMonthly || '',
                stripePriceEnterpriseYearly: configData.stripePriceEnterpriseYearly || '',
                planBasicMonthlyAmount: configData.planBasicMonthlyAmount ?? null,
                planBasicMonthlyCurrency: configData.planBasicMonthlyCurrency || null,
                planProMonthlyAmount: configData.planProMonthlyAmount ?? null,
                planProMonthlyCurrency: configData.planProMonthlyCurrency || null,
                planEnterpriseMonthlyAmount: configData.planEnterpriseMonthlyAmount ?? null,
                planEnterpriseMonthlyCurrency: configData.planEnterpriseMonthlyCurrency || null,
                updatedAt: configData.updatedAt,
                updatedBy: configData.updatedBy || null
            };
            setPaymentConfigForm({
                paypalEnabled: sanitized.paypalEnabled,
                paypalClientId: sanitized.paypalClientId || '',
                paypalSecretKey: sanitized.paypalSecretKey || '',
                stripeEnabled: sanitized.stripeEnabled,
                stripePublicKey: sanitized.stripePublicKey || '',
                stripeSecretKey: sanitized.stripeSecretKey || '',
                stripeWebhookSecret: sanitized.stripeWebhookSecret || '',
                stripePriceBasicMonthly: sanitized.stripePriceBasicMonthly || '',
                stripePriceBasicYearly: sanitized.stripePriceBasicYearly || '',
                stripePriceProMonthly: sanitized.stripePriceProMonthly || '',
                stripePriceProYearly: sanitized.stripePriceProYearly || '',
                stripePriceEnterpriseMonthly: sanitized.stripePriceEnterpriseMonthly || '',
                stripePriceEnterpriseYearly: sanitized.stripePriceEnterpriseYearly || '',
                planBasicMonthlyAmount: String(sanitized.planBasicMonthlyAmount ?? ''),
                planBasicMonthlyCurrency: sanitized.planBasicMonthlyCurrency || 'USD',
                planProMonthlyAmount: String(sanitized.planProMonthlyAmount ?? ''),
                planProMonthlyCurrency: sanitized.planProMonthlyCurrency || 'USD',
                planEnterpriseMonthlyAmount: String(sanitized.planEnterpriseMonthlyAmount ?? ''),
                planEnterpriseMonthlyCurrency: sanitized.planEnterpriseMonthlyCurrency || 'USD'
            });
            onUpdatePaymentGatewayConfig?.(sanitized);
            setPaymentNotice({ type: 'success', text: t.paymentGatewaysSaveSuccess || 'Payment gateways updated successfully.' });
        } catch (error) {
            setPaymentNotice({
                type: 'error',
                text: error instanceof Error ? error.message : t.paymentGatewaysSaveError || 'Unable to update payment gateways'
            });
        } finally {
            setIsSavingPaymentConfig(false);
        }
    };

    const handleSaveAIConfig = async (event?: React.FormEvent) => {
        event?.preventDefault();
        const trimmedApiKey = aiConfigForm.apiKey.trim();
        const resolvedAiEnabled = aiConfigForm.aiEnabled || Boolean(trimmedApiKey);
        if (resolvedAiEnabled && !trimmedApiKey) {
            setAiNotice({
                type: 'error',
                text: t.aiKeyRequired || 'API Key is required when AI is enabled'
            });
            return;
        }
        setIsSavingAIConfig(true);
        setAiNotice(null);
        try {
            const payloadBody = {
                aiEnabled: resolvedAiEnabled,
                aiProvider: aiConfigForm.aiProvider,
                aiModel: aiConfigForm.aiModel.trim(),
                apiKey: trimmedApiKey,
                maxTokens: aiConfigForm.maxTokens,
                temperature: aiConfigForm.temperature,
                updatedBy: user?.id
            };
            const response = await fetch(aiConfigEndpoint, {
                method: 'PUT',
                credentials: 'include',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payloadBody)
            });
            const payload = await response.json().catch(() => ({}));
            if (!response.ok) {
                throw new Error(payload?.error || t.aiConfigSaveError || 'Unable to update AI configuration');
            }
            resetAIConfigCache();
            await fetchResolvedAIConfig(true).catch(() => null);
            setAiConfigForm((prev) => ({
                ...prev,
                aiEnabled: resolvedAiEnabled,
                apiKey: trimmedApiKey
            }));
            setAiNotice({ type: 'success', text: t.aiConfigSaveSuccess || 'AI configuration updated successfully.' });
        } catch (error) {
            setAiNotice({
                type: 'error',
                text: error instanceof Error ? error.message : t.aiConfigSaveError || 'Unable to update AI configuration'
            });
        } finally {
            setIsSavingAIConfig(false);
        }
    };

    const handleTestAIConfig = async () => {
        if (!aiConfigForm.apiKey.trim()) {
            setAiNotice({
                type: 'error',
                text: t.aiKeyRequired || 'API Key is required for testing'
            });
            return;
        }
        setIsTestingAI(true);
        setAiNotice(null);
        try {
            const response = await fetch(`${aiConfigEndpoint}/test`, {
                method: 'POST',
                credentials: 'include',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    apiKey: aiConfigForm.apiKey.trim(),
                    provider: aiConfigForm.aiProvider,
                    model: aiConfigForm.aiModel.trim()
                })
            });
            const payload = await response.json().catch(() => ({}));
            if (!response.ok) {
                throw new Error(payload?.error || t.aiTestFailed || 'AI connection test failed');
            }
            setAiNotice({ 
                type: 'success', 
                text: t.aiTestSuccess || 'AI connection test successful!' 
            });
        } catch (error) {
            setAiNotice({
                type: 'error',
                text: error instanceof Error ? error.message : t.aiTestFailed || 'AI connection test failed'
            });
        } finally {
            setIsTestingAI(false);
        }
    };

    // Load AI Config on mount
    useEffect(() => {
        const loadAIConfig = async () => {
            try {
                const response = await fetch(aiConfigEndpoint, { credentials: 'include' });
                if (response.ok) {
                    const payload = await response.json();
                    if (payload.success && payload.data) {
                        setAiConfigForm({
                            aiEnabled: payload.data.aiEnabled || false,
                            aiProvider: payload.data.aiProvider || 'gemini',
                            aiModel: payload.data.aiModel || 'gemini-2.5-flash',
                            apiKey: '', // Never load the actual key for security
                            maxTokens: payload.data.maxTokens || 4096,
                            temperature: payload.data.temperature || 0.7
                        });
                    }
                }
            } catch (error) {
                console.error('Failed to load AI config:', error);
            }
        };
        loadAIConfig();
    }, []);

    const handleManualCreditAdjust = async (event: React.FormEvent) => {
        event.preventDefault();
        if (!creditTargetUser) {
            setCreditNotice({ type: 'error', text: t?.selectUser || 'Select a user first.' });
            return;
        }
        setIsAdjustingCredits(true);
        setCreditNotice(null);
        try {
            const response = await fetch('/api/credits/adjust', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    userId: creditTargetUser,
                    amount: creditAmount,
                    actionType: creditAction,
                    reason: creditReason,
                    actorId: user?.id
                })
            });
            const payload = await response.json().catch(() => ({}));
            if (!response.ok) {
                throw new Error(payload?.error || 'Unable to adjust credits');
            }
            const nextUsers = users.map((u) => (u.id === payload.user.id ? payload.user : u));
            syncUsers(nextUsers);
            onAddCreditTransaction?.(payload.transaction);
            setCreditNotice({ type: 'success', text: t?.creditAdjustSuccess || 'Credits updated successfully.' });
            setCreditReason('');
            await fetchCreditLeaderboard().catch((error) => {
                console.error('Leaderboard refresh after credit adjustment failed', error);
            });
        } catch (error) {
            setCreditNotice({
                type: 'error',
                text: error instanceof Error ? error.message : 'Unable to adjust credits right now.'
            });
        } finally {
            setIsAdjustingCredits(false);
        }
    };

    const handleOptionFormChange = (field: keyof typeof optionForm, value: string) => {
        setOptionForm((prev) => ({
            ...prev,
            [field]: field === 'requiredCredits' ? Number(value) : value
        }));
    };

    const handleCreateOption = async (event: React.FormEvent) => {
        event.preventDefault();
        setIsSavingOption(true);
        setOptionNotice(null);
        try {
            let metadataPayload: Record<string, any> | undefined;
            if (optionForm.metadataText.trim()) {
                try {
                    metadataPayload = JSON.parse(optionForm.metadataText);
                } catch {
                    throw new Error('Metadata must be valid JSON.');
                }
            }
            const response = await fetch('/api/credits/options', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    title: optionForm.title,
                    type: optionForm.type,
                    description: optionForm.description,
                    requiredCredits: optionForm.requiredCredits,
                    metadata: metadataPayload,
                    createdBy: user?.id
                })
            });
            const payload = await response.json().catch(() => ({}));
            if (!response.ok) {
                throw new Error(payload?.error || 'Failed to create redemption option');
            }
            onUpsertCreditOption?.(payload);
            setOptionForm({ title: '', type: 'FREE_COURSE', description: '', requiredCredits: 3000, metadataText: '' });
            setOptionNotice({ type: 'success', text: t?.optionCreated || 'Redemption option added.' });
        } catch (error) {
            setOptionNotice({
                type: 'error',
                text: error instanceof Error ? error.message : 'Unable to create redemption option.'
            });
        } finally {
            setIsSavingOption(false);
        }
    };

    const handleToggleOption = async (option: CreditRedemptionOption) => {
        try {
            const response = await fetch(`/api/credits/options/${option.id}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ isActive: !option.isActive })
            });
            const payload = await response.json().catch(() => ({}));
            if (!response.ok) {
                throw new Error(payload?.error || 'Failed to update option');
            }
            onUpsertCreditOption?.(payload);
            setOptionNotice({
                type: 'success',
                text: option.isActive ? (t?.optionDisabled || 'Option disabled.') : (t?.optionEnabled || 'Option enabled.')
            });
        } catch (error) {
            setOptionNotice({
                type: 'error',
                text: error instanceof Error ? error.message : 'Unable to update redemption option.'
            });
        }
    };

    useEffect(() => {
        if (activeTab !== 'PAGES') return;
        const controller = new AbortController();
        requestPageContent(selectedPageSlug, { signal: controller.signal });
        if (selectedPageSlug === 'career') {
            fetchCareerApplications({ silent: true });
        }
        return () => {
            controller.abort();
            careerApplicationsAbortRef.current?.abort();
        };
    }, [activeTab, selectedPageSlug, requestPageContent, fetchCareerApplications]);

    useEffect(() => {
        if (activeTab !== 'OFFERS') return;
        fetchDiscountsFromServer().catch((error) => {
            console.error('Discount refresh while viewing Offers tab failed', error);
        });
    }, [activeTab, fetchDiscountsFromServer]);

    useEffect(() => {
        if (activeTab !== 'CREDITS') return;
        fetchCreditLeaderboard().catch((error) => {
            console.error('Credit leaderboard refresh failed', error);
        });
    }, [activeTab, fetchCreditLeaderboard]);

    // SEO Management - Fetch SEO settings on tab load
    useEffect(() => {
        if (activeTab === 'SEO' && seoSettings.length === 0 && !isLoadingSeo) {
            fetchSeoSettings();
        }
    }, [activeTab]);

    const fetchSeoSettings = async () => {
        setIsLoadingSeo(true);
        setSeoNotice(null);
        try {
            const response = await fetch(seoEndpoint);
            const data = await response.json();
            if (response.ok && data.success) {
                setSeoSettings(data.data || []);
            } else {
                setSeoNotice({ type: 'error', text: t.seoLoadError || 'Failed to load SEO settings' });
            }
        } catch (error) {
            console.error('SEO fetch error:', error);
            setSeoNotice({ type: 'error', text: t.seoLoadError || 'Failed to load SEO settings' });
        } finally {
            setIsLoadingSeo(false);
        }
    };

    const buildSeoPayload = () => {
        const priorityValue = seoForm.sitemap_priority.trim();
        const sitemap_priority = priorityValue ? Number(priorityValue) : undefined;
        return {
            ...seoForm,
            sitemap_priority: Number.isFinite(sitemap_priority) ? sitemap_priority : undefined,
            sitemap_changefreq: seoForm.sitemap_changefreq || undefined
        };
    };

    const handleSeoFormSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        
        if (!seoForm.page_path.trim()) {
            setSeoFormErrors({ page_path: t.seoPagePathRequired || (lang === 'ar' ? 'مسار الصفحة مطلوب' : 'Page path is required') });
            return;
        }

        setIsSavingSeo(true);
        setSeoNotice(null);
        setSeoFormErrors({});

        try {
            const url = editingSeo 
                ? `${seoEndpoint}/${editingSeo.id}`
                : seoEndpoint;
            const method = editingSeo ? 'PUT' : 'POST';

            const response = await fetch(url, {
                method,
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(buildSeoPayload())
            });

            const data = await response.json();

            if (response.ok && data.success) {
                if (editingSeo) {
                    setSeoSettings(prev => prev.map(s => s.id === editingSeo.id ? data.data : s));
                    setSeoNotice({ type: 'success', text: t.seoUpdateSuccess || 'SEO setting updated successfully' });
                } else {
                    setSeoSettings(prev => [data.data, ...prev]);
                    setSeoNotice({ type: 'success', text: t.seoSaveSuccess || 'SEO setting saved successfully' });
                }
                setEditingSeo(null);
                setCreatingSeo(false);
                setSeoForm({
                    page_path: '',
                    title_en: '',
                    title_ar: '',
                    description_en: '',
                    description_ar: '',
                    keywords_en: '',
                    keywords_ar: '',
                    canonical_url: '',
                    robots: '',
                    indexable: true,
                    og_title_en: '',
                    og_title_ar: '',
                    og_description_en: '',
                    og_description_ar: '',
                    og_image_url: '',
                    og_type: 'website',
                    og_site_name: '',
                    twitter_card: 'summary_large_image',
                    twitter_title_en: '',
                    twitter_title_ar: '',
                    twitter_description_en: '',
                    twitter_description_ar: '',
                    twitter_image_url: '',
                    jsonld_en: '',
                    jsonld_ar: '',
                    locale: '',
                    locale_alternate: '',
                    sitemap_priority: '',
                    sitemap_changefreq: ''
                });
            } else {
                setSeoNotice({ type: 'error', text: data.error || (editingSeo ? t.seoUpdateError : t.seoSaveError) || 'Failed to save SEO setting' });
            }
        } catch (error) {
            console.error('SEO save error:', error);
            setSeoNotice({ type: 'error', text: (editingSeo ? t.seoUpdateError : t.seoSaveError) || 'Failed to save SEO setting' });
        } finally {
            setIsSavingSeo(false);
        }
    };

    const handleDeleteSeo = async (id: string) => {
        const confirmed = await confirm(t.seoConfirmDelete || 'Are you sure you want to delete this SEO setting?');
        if (!confirmed) return;

        try {
            const response = await fetch(`${seoEndpoint}/${id}`, {
                method: 'DELETE'
            });

            const data = await response.json();

            if (response.ok) {
                setSeoSettings(prev => prev.filter(s => s.id !== id));
                setSeoNotice({ type: 'success', text: t.seoDeleteSuccess || 'SEO setting deleted successfully' });
            } else {
                setSeoNotice({ type: 'error', text: data.error || t.seoDeleteError || 'Failed to delete SEO setting' });
            }
        } catch (error) {
            console.error('SEO delete error:', error);
            setSeoNotice({ type: 'error', text: t.seoDeleteError || 'Failed to delete SEO setting' });
        }
    };

