                                                    {isSavingPage ? (
                                                        <span className="inline-flex items-center gap-2">
                                                            <RefreshCw className="h-4 w-4 animate-spin" />
                                                            {t.pageSaving || 'Saving...'}
                                                        </span>
                                                    ) : (
                                                        t.pageSave || 'Save Page'
                                                    )}
